<?php namespace App\Services; use App\Services\WhatsApp\WhatsAppProviderInterface; use App\Services\WhatsApp\LogProvider; use App\Services\WhatsApp\FonnteProvider; use App\Services\WhatsApp\RuangWaProvider; class WhatsAppService { public static function make(): WhatsAppProviderInterface { $provider = env("WA_PROVIDER", "log"); switch (strtolower($provider)) { case "fonnte": return new FonnteProvider(); case "ruangwa": return new RuangWaProvider(); case "log": default: return new LogProvider(); } } public static function send(string $phone, string $message): bool { return self::make()->sendMessage($phone, $message); } }
